package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

/**
 * Query-selected layout for masks stored as slices in a shared {@code long[]} arena.
 *
 * <p>
 * One layout instance is selected before planning. The one- and two-word cases avoid a loop; larger masks use the same
 * operations over a contiguous slice.
 */
@PackedHotPath
final class PackedMaskLayout {

	enum Kind {
		ONE_WORD,
		TWO_WORD,
		MULTI_WORD
	}

	private final int symbolCount;
	private final int wordCount;
	private final long lastWordMask;
	private final Kind kind;

	private PackedMaskLayout(int symbolCount) {
		this.symbolCount = symbolCount;
		wordCount = Math.max(1, (symbolCount + Long.SIZE - 1) >>> 6);
		kind = wordCount == 1 ? Kind.ONE_WORD : wordCount == 2 ? Kind.TWO_WORD : Kind.MULTI_WORD;
		int remainingBits = symbolCount & (Long.SIZE - 1);
		lastWordMask = remainingBits == 0 ? -1L : (1L << remainingBits) - 1L;
	}

	static PackedMaskLayout forSymbols(int symbolCount) {
		if (symbolCount < 0) {
			throw new IllegalArgumentException("symbol count must be non-negative");
		}
		return new PackedMaskLayout(symbolCount);
	}

	Kind kind() {
		return kind;
	}

	int wordCount() {
		return wordCount;
	}

	void set(long[] arena, int offset, int symbol) {
		checkSymbol(symbol);
		arena[offset + (symbol >>> 6)] |= 1L << symbol;
	}

	boolean contains(long[] arena, int offset, int symbol) {
		checkSymbol(symbol);
		return (arena[offset + (symbol >>> 6)] & 1L << symbol) != 0L;
	}

	boolean intersects(long[] leftArena, int leftOffset, long[] rightArena, int rightOffset) {
		return switch (kind) {
		case ONE_WORD -> (leftArena[leftOffset] & rightArena[rightOffset]) != 0L;
		case TWO_WORD -> (leftArena[leftOffset] & rightArena[rightOffset]) != 0L
				|| (leftArena[leftOffset + 1] & rightArena[rightOffset + 1]) != 0L;
		case MULTI_WORD -> intersectsMulti(leftArena, leftOffset, rightArena, rightOffset);
		};
	}

	boolean containsAll(long[] containerArena, int containerOffset, long[] containedArena, int containedOffset) {
		return switch (kind) {
		case ONE_WORD -> containsWord(containerArena[containerOffset], containedArena[containedOffset]);
		case TWO_WORD -> containsWord(containerArena[containerOffset], containedArena[containedOffset])
				&& containsWord(containerArena[containerOffset + 1], containedArena[containedOffset + 1]);
		case MULTI_WORD -> containsAllMulti(containerArena, containerOffset, containedArena, containedOffset);
		};
	}

	void union(long[] destinationArena, int destinationOffset, long[] leftArena, int leftOffset, long[] rightArena,
			int rightOffset) {
		switch (kind) {
		case ONE_WORD -> destinationArena[destinationOffset] = (leftArena[leftOffset] | rightArena[rightOffset])
				& lastWordMask;
		case TWO_WORD -> {
			destinationArena[destinationOffset] = leftArena[leftOffset] | rightArena[rightOffset];
			destinationArena[destinationOffset + 1] = (leftArena[leftOffset + 1] | rightArena[rightOffset + 1])
					& lastWordMask;
		}
		case MULTI_WORD -> unionMulti(destinationArena, destinationOffset, leftArena, leftOffset, rightArena,
				rightOffset);
		}
	}

	int cardinality(long[] arena, int offset) {
		return switch (kind) {
		case ONE_WORD -> Long.bitCount(arena[offset]);
		case TWO_WORD -> Long.bitCount(arena[offset]) + Long.bitCount(arena[offset + 1]);
		case MULTI_WORD -> cardinalityMulti(arena, offset);
		};
	}

	private boolean intersectsMulti(long[] leftArena, int leftOffset, long[] rightArena, int rightOffset) {
		for (int i = 0; i < wordCount; i++) {
			if ((leftArena[leftOffset + i] & rightArena[rightOffset + i]) != 0L) {
				return true;
			}
		}
		return false;
	}

	private boolean containsAllMulti(long[] containerArena, int containerOffset, long[] containedArena,
			int containedOffset) {
		for (int i = 0; i < wordCount; i++) {
			if (!containsWord(containerArena[containerOffset + i], containedArena[containedOffset + i])) {
				return false;
			}
		}
		return true;
	}

	private void unionMulti(long[] destinationArena, int destinationOffset, long[] leftArena, int leftOffset,
			long[] rightArena, int rightOffset) {
		for (int i = 0; i < wordCount; i++) {
			destinationArena[destinationOffset + i] = leftArena[leftOffset + i] | rightArena[rightOffset + i];
		}
		destinationArena[destinationOffset + wordCount - 1] &= lastWordMask;
	}

	private int cardinalityMulti(long[] arena, int offset) {
		int cardinality = 0;
		for (int i = 0; i < wordCount; i++) {
			cardinality += Long.bitCount(arena[offset + i]);
		}
		return cardinality;
	}

	private static boolean containsWord(long container, long contained) {
		return (container & contained) == contained;
	}

	private void checkSymbol(int symbol) {
		if (symbol < 0 || symbol >= symbolCount) {
			throw new IndexOutOfBoundsException("symbol " + symbol + " outside [0, " + symbolCount + ")");
		}
	}
}
